export interface CaseStudy {
  slug: string;
  title: string;
  titleUrdu: string;
  date: string; // YYYY-MM-DD
  location: string;
  category: "healthcare" | "education" | "livelihood" | "ration" | "welfare" | "emergency";
  beneficiary: string;
  beneficiaryAge?: number;
  summary: string;
  summaryUrdu: string;
  story: string; // Full narrative (English)
  storyUrdu: string;
  aidProvided: string[];
  totalAid?: string; // e.g. "Rs 20,000"
  outcome: string;
  outcomeUrdu: string;
  images: string[]; // paths relative to /public
  featured?: boolean;
  tags: string[];
}

export interface Program {
  slug: string;
  title: string;
  titleUrdu: string;
  description: string;
  descriptionUrdu: string;
  icon: string; // emoji or icon name
  stats: { label: string; value: string; labelUrdu: string }[];
  images: string[];
  cases: string[]; // slugs of related case studies
  active: boolean;
}

export interface TeamMember {
  name: string;
  nameUrdu: string;
  role: string;
  roleUrdu: string;
  location: string;
  image?: string;
}

export interface TimelineEvent {
  date: string;
  title: string;
  titleUrdu: string;
  description: string;
  descriptionUrdu: string;
  category: string;
}

